import React, { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import './GeminiChat.css';

function GeminiChat() {
    const [messages, setMessages] = useState([
        { role: 'model', text: 'Hello! I am your AI Support Assistant powered by Gemini. How can I help you today?' }
    ]);
    const [input, setInput] = useState('');
    const [loading, setLoading] = useState(false);
    const messagesEndRef = useRef(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages]);

    const handleSend = async (e) => {
        e.preventDefault();
        if (!input.trim() || loading) return;

        const userMessage = input.trim();
        setInput('');
        setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
        setLoading(true);

        try {
            const baseUrl = process.env.REACT_APP_API_BASE_URL || '/api';
            const cleanBaseUrl = baseUrl.endsWith('/') ? baseUrl.slice(0, -1) : baseUrl;

            const res = await fetch(`${cleanBaseUrl}/ai/chat`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    message: userMessage,
                    history: messages.map(m => ({
                        role: m.role,
                        parts: [{ text: m.text }]
                    }))
                }),
            });

            const data = await res.json();
            if (res.ok) {
                setMessages(prev => [...prev, { role: 'model', text: data.reply }]);
            } else {
                setMessages(prev => [...prev, { role: 'model', text: `Error: ${data.message}. Please ensure your API key is set in the backend .env file.` }]);
            }
        } catch (err) {
            console.error(err);
            setMessages(prev => [...prev, { role: 'model', text: 'Network error. Could not reach the AI gateway.' }]);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="home-container">
            <nav className="navbar">
                <Link to="/" className="nav-brand">PowerGrid AI</Link>
                <Link to="/my-tickets" className="cta-secondary" style={{ padding: '8px 20px' }}>My Tickets</Link>
            </nav>

            <div className="chat-container">
                <div className="chat-window">
                    <div className="chat-header">
                        <h3>AI Support Assistant</h3>
                        <span className="status-indicator">Powered by Gemini</span>
                    </div>

                    <div className="messages-list">
                        {messages.map((msg, idx) => (
                            <div key={idx} className={`message-bubble ${msg.role}`}>
                                <div className="bubble-content">
                                    {msg.text}
                                </div>
                            </div>
                        ))}
                        {loading && (
                            <div className="message-bubble model loading">
                                <div className="typing-indicator">
                                    <span></span><span></span><span></span>
                                </div>
                            </div>
                        )}
                        <div ref={messagesEndRef} />
                    </div>

                    <form onSubmit={handleSend} className="chat-input-area">
                        <input
                            type="text"
                            placeholder="Ask anything about our services..."
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            disabled={loading}
                        />
                        <button type="submit" disabled={loading || !input.trim()}>
                            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                <path d="M22 2L11 13M22 2l-7 20-4-9-9-4 20-7z" />
                            </svg>
                        </button>
                    </form>
                </div>
            </div>
        </div>
    );
}

export default GeminiChat;
